const staticData = $getWorkflowStaticData('global');
const stdout = ($json.stdout || '').trim();
const lines = stdout ? stdout.split('\n').map(line => line.trim()).filter(Boolean) : [];
const processed = staticData.processedFiles || {};
const items = [];

for (const line of lines) {
  const sep = line.indexOf('|');
  if (sep === -1) continue;
  const modifiedRaw = line.slice(0, sep).trim();
  const filepath = line.slice(sep + 1).trim();
  if (!filepath) continue;

  const filename = filepath.split('/').pop();
  const modifiedEpoch = Number(modifiedRaw);
  const prior = processed[filepath];

  if (prior && Number(prior.modifiedEpoch) === modifiedEpoch) {
    continue;
  }

  items.push({ json: { filepath, filename, modifiedEpoch } });
}

return items;

const fs = require('fs');
const filepath = $json.filepath;
if (!filepath) throw new Error('Missing filepath');
const content = fs.readFileSync(filepath, 'utf8');
return [{ json: { filepath: $json.filepath, filename: $json.filename, modifiedEpoch: $json.modifiedEpoch, content } }];

const staticData = $getWorkflowStaticData('global');
const processed = staticData.processedFiles || {};
const input = $('Read TXT Content').item.json;
const child = $json;

processed[input.filepath] = {
  filename: input.filename,
  modifiedEpoch: input.modifiedEpoch,
  processedAt: new Date().toISOString(),
  childResponse: child,
};

staticData.processedFiles = processed;

return [{
  json: {
    ok: true,
    filepath: input.filepath,
    filename: input.filename,
    modifiedEpoch: input.modifiedEpoch,
    childResponse: child,
  }
}];
